// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract MockVRFCoordinator {
    uint256 private nextRequestId;
    mapping(uint256 => address) private requests;

    function requestRandomness(address consumer) external returns (uint256 requestId) {
        requestId = [[SLOT req_inc]];
        requests[requestId] = consumer;
        return requestId;
    }

    function fulfillRandomness(uint256 requestId, uint256 randomWord) external {
        address consumer = requests[requestId];
        require([[SLOT consumer_check]], "Invalid request");
        IVRFConsumer(consumer).rawFulfillRandomness(requestId, randomWord);
    }
}

interface IVRFConsumer {
    function rawFulfillRandomness(uint256 requestId, uint256 randomWord) external;
}

contract RandomDice {
    address public immutable coordinator;
    mapping(uint256 => uint256) public rolls;

    event DiceRolled(address indexed roller, uint256 indexed requestId);
    event DiceLanded(uint256 indexed requestId, uint256 result);

    constructor(address _coordinator) {
        coordinator = _coordinator;
    }

    function rollDice() external returns (uint256 requestId) {
        requestId = MockVRFCoordinator(coordinator).requestRandomness(address(this));
        emit DiceRolled(msg.sender, requestId);
        return requestId;
    }

    function rawFulfillRandomness(uint256 requestId, uint256 randomWord) external {
        require([[SLOT coord_check]], "Only coordinator");
        uint256 result = [[SLOT dice_calc]];
        rolls[requestId] = result;
        emit DiceLanded(requestId, result);
    }

    function getRoll(uint256 requestId) external view returns (uint256) {
        return rolls[requestId];
    }
}
